fn route_request(req: &Request) -> &'static str {
    let path = req.get_path();

    if path.starts_with("/api/") || path.starts_with("/v1/") || path.starts_with("/v2/") {
        BACKEND_API
    } else if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.starts_with("/css/")
        || path.starts_with("/js/")
    {
        BACKEND_STATIC
    } else if path.starts_with("/auth/")
        || path.starts_with("/login")
        || path.starts_with("/logout")
        || path.starts_with("/oauth/")
    {
        BACKEND_AUTH
    } else {
        BACKEND_DEFAULT
    }
}

fn find_backend_config<'a>(
    configs: &'a [BackendConfig],
    backend_name: &str,
) -> Option<&'a BackendConfig> {
    configs.iter().find(|c| c.name == backend_name)
}

fn add_request_headers(req: &mut Request, config: &BackendConfig) {
    req.set_header(header::HOST, config.host);
    req.set_header("X-Forwarded-Proto", if config.use_tls { "https" } else { "http" });
    req.set_header("X-Backend-Name", config.name);
    req.set_header("X-Request-Id", generate_request_id());
}

fn generate_request_id() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let duration = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default();
    format!("req-{}-{}", duration.as_secs(), duration.subsec_nanos())
}

fn handle_health_check() -> Response {
    Response::from_status(StatusCode::OK)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(r#"{"status":"healthy","service":"edge-router"}"#)
}

fn handle_options_request(req: &Request) -> Response {
    Response::from_status(StatusCode::NO_CONTENT)
        .with_header(header::ACCESS_CONTROL_ALLOW_ORIGIN, "*")
        .with_header(
            header::ACCESS_CONTROL_ALLOW_METHODS,
            "GET, POST, PUT, DELETE, PATCH, OPTIONS",
        )
        .with_header(
            header::ACCESS_CONTROL_ALLOW_HEADERS,
            "Content-Type, Authorization, X-Requested-With",
        )
        .with_header(header::ACCESS_CONTROL_MAX_AGE, "86400")
}

fn create_error_response(status: StatusCode, message: &str) -> Response {
    let body = format!(
        r#"{{"error":true,"status":{},"message":"{}"}}"#,
        status.as_u16(),
        message
    );
    Response::from_status(status)
        .with_content_type(mime::APPLICATION_JSON)
        .with_body(body)
}

fn add_security_headers(resp: &mut Response) {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains; preload",
    );
}

fn add_cache_headers(resp: &mut Response, backend_name: &str) {
    match backend_name {
        BACKEND_STATIC => {
            resp.set_header(header::CACHE_CONTROL, "public, max-age=86400, immutable");
        }
        BACKEND_API => {
            resp.set_header(header::CACHE_CONTROL, "no-store, no-cache, must-revalidate");
            resp.set_header(header::PRAGMA, "no-cache");
        }
        BACKEND_AUTH => {
            resp.set_header(header::CACHE_CONTROL, "no-store, no-cache, must-revalidate, private");
            resp.set_header(header::PRAGMA, "no-cache");
        }
        _ => {
            resp.set_header(header::CACHE_CONTROL, "public, max-age=300");
        }
    }
}

fn send_to_backend(mut req: Request, config: &BackendConfig) -> Result<Response, Error> {
    add_request_headers(&mut req, config);

    let backend = Backend::from_name(config.name)?;

    match req.send(backend) {
        Ok(mut resp) => {
            add_security_headers(&mut resp);
            add_cache_headers(&mut resp, config.name);
            resp.set_header("X-Served-By", "fastly-edge-router");
            resp.set_header("X-Backend", config.name);
            Ok(resp)
        }
        Err(e) => {
            eprintln!(
                "Error sending request to backend {}: {:?}",
                config.name, e
            );
            Ok(create_error_response(
                StatusCode::BAD_GATEWAY,
                &format!("Backend {} is unavailable", config.name),
            ))
        }
    }
}

