#[fastly::main]
fn main(req: Request) -> Result<Response, Error> {
    // Handle health check endpoint
    if req.get_path() == "/health" || req.get_path() == "/__health" {
        return Ok(handle_health_check());
    }

    // Handle CORS preflight requests
    if req.get_method() == Method::OPTIONS {
        return Ok(handle_options_request(&req));
    }

    // Check rate limiting
    if let Some(rate_limit_response) = handle_rate_limiting(&req) {
        return Ok(rate_limit_response);
    }

    // Get backend configurations
    let configs = get_backend_configs();

    // Route the request to the appropriate backend
    let backend_name = route_request(&req);

    // Log the request
    log_request(&req, backend_name);

    // Find the backend configuration
    let config = match find_backend_config(&configs, backend_name) {
        Some(c) => c,
        None => {
            return Ok(create_error_response(
                StatusCode::INTERNAL_SERVER_ERROR,
                "Backend configuration not found",
            ));
        }
    };

    // Send the request to the backend
    send_to_backend(req, config)
}